import React from 'react';
import { Menu } from 'antd';
import { MenuItem } from '../../Layout/app/Types';
import { menuData } from './MenuItemsData';

const { SubMenu } = Menu;

const MegaMenuColumn: React.FC<{ items: MenuItem[] }> = ({ items }) => {
  return (
    <Menu mode="vertical">
      {items.map((item) => (
        <Menu.Item key={item.key}>
          <a href={`/${item.key}`}>{item.label}</a>
        </Menu.Item>
      ))}
    </Menu>
  );
};

const generateMenuItems = (items: MenuItem[]): React.ReactNode => {
  return items.map((item) => {
    if (item.children) {
      return (
        <SubMenu key={item.key} title={item.label}>
          <div className="mega-menu">
            <div className="mega-menu-column">
              <MegaMenuColumn items={item.children.slice(0, 4)} />
            </div>
            <div className="mega-menu-column">
              <MegaMenuColumn items={item.children.slice(4, 8)} />
            </div>
            <div className="mega-menu-column">
              <MegaMenuColumn items={item.children.slice(8, 12)} />
            </div>
            {/* Add more columns as needed */}
          </div>
        </SubMenu>
      );
    } else {
      return (
        <Menu.Item key={item.key}>
          <a href={`/${item.key}`}>{item.label}</a>
        </Menu.Item>
      );
    }
  });
};

const MenuItems: React.FC<{ items: MenuItem[] }> = ({ items }) => {
  return <Menu mode="horizontal">{generateMenuItems(items)}</Menu>;
};

const App = () => {
  return <MenuItems items={menuData} />;
};

export default App;
